class WebSocketServer:
    def __init__(self, port=8080):
        self.port = port
        self.server_socket = None
        self.clients = []
        self.running = False
        
    def start(self):
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_socket.bind(('0.0.0.0', self.port))
        self.server_socket.listen(5)
        self.server_socket.setblocking(False)
        self.running = True
        print(f"WebSocket server started on port {self.port}")
        
    def stop(self):
        self.running = False
        for client in self.clients:
            try:
                client.close()
            except:
                pass
        self.clients = []
        if self.server_socket:
            self.server_socket.close()
        print("WebSocket server stopped")
        
    def accept_connection(self):
        try:
            client_socket, addr = self.server_socket.accept()
            client_socket.setblocking(False)
            print(f"New connection from {addr}")
            return client_socket, addr
        except OSError:
            return None, None
            
    def handshake(self, client_socket):
        try:
            request = b""
            while True:
                try:
                    chunk = client_socket.recv(1024)
                    if not chunk:
                        return False
                    request += chunk
                    if b"\r\n\r\n" in request:
                        break
                except OSError:
                    time.sleep(0.01)
                    continue
                    
            request_str = request.decode('utf-8')
            
            if 'Upgrade: websocket' not in request_str:
                return False
                
            key = None
            for line in request_str.split('\r\n'):
                if line.startswith('Sec-WebSocket-Key:'):
                    key = line.split(':', 1)[1].strip()
                    break
                    
            if not key:
                return False
                
            magic = '258EAFA5-E914-47DA-95CA-C5AB0DC85B11'
            accept_key = key + magic
            sha1 = hashlib.sha1(accept_key.encode()).digest()
            accept_key = binascii.b2a_base64(sha1).strip().decode('utf-8')
            
            response = (
                'HTTP/1.1 101 Switching Protocols\r\n'
                'Upgrade: websocket\r\n'
                'Connection: Upgrade\r\n'
                f'Sec-WebSocket-Accept: {accept_key}\r\n'
                '\r\n'
            )
            
            client_socket.send(response.encode())
            return True
            
        except Exception as e:
            print(f"Handshake error: {e}")
            return False
            
    def parse_frame(self, data):
        if len(data) < 2:
            return None, None
            
        byte1 = data[0]
        byte2 = data[1]
        
        fin = (byte1 & 0x80) != 0
        opcode = byte1 & 0x0F
        masked = (byte2 & 0x80) != 0
        payload_len = byte2 & 0x7F
        
        offset = 2
        
        if payload_len == 126:
            if len(data) < 4:
                return None, None
            payload_len = struct.unpack('>H', data[2:4])[0]
            offset = 4
        elif payload_len == 127:
            if len(data) < 10:
                return None, None
            payload_len = struct.unpack('>Q', data[2:10])[0]
            offset = 10
            
        if masked:
            if len(data) < offset + 4:
                return None, None
            mask = data[offset:offset + 4]
            offset += 4
        else:
            mask = None
            
        if len(data) < offset + payload_len:
            return None, None
            
        payload = bytearray(data[offset:offset + payload_len])
        
        if mask:
            for i in range(len(payload)):
                payload[i] ^= mask[i % 4]
                
        return opcode, bytes(payload)
        
    def create_frame(self, payload, opcode=0x01):
        frame = bytearray()
        frame.append(0x80 | opcode)
        
        payload_len = len(payload)
        
        if payload_len < 126:
            frame.append(payload_len)
        elif payload_len < 65536:
            frame.append(126)
            frame.extend(struct.pack('>H', payload_len))
        else:
            frame.append(127)
            frame.extend(struct.pack('>Q', payload_len))
            
        frame.extend(payload)
        return bytes(frame)
        
    def send_message(self, client_socket, message):
        try:
            if isinstance(message, dict):
                message = json.dumps(message)
            frame = self.create_frame(message.encode())
            client_socket.send(frame)
            return True
        except Exception as e:
            print(f"Send error: {e}")
            return False
            
    def receive_message(self, client_socket):
        try:
            data = client_socket.recv(4096)
            if not data:
                return None
                
            opcode, payload = self.parse_frame(data)
            
            if opcode is None:
                return None
            elif opcode == 0x08:
                return 'CLOSE'
            elif opcode == 0x09:
                pong_frame = self.create_frame(payload, opcode=0x0A)
                client_socket.send(pong_frame)
                return None
            elif opcode == 0x01:
                return payload.decode('utf-8')
            else:
                return None
                
        except OSError:
            return None
        except Exception as e:
            print(f"Receive error: {e}")
            return None
            
    def broadcast(self, message):
        disconnected = []
        for client in self.clients:
            if not self.send_message(client, message):
                disconnected.append(client)
                
        for client in disconnected:
            try:
                client.close()
            except:
                pass
            self.clients.remove(client)
            
    def run(self):
        while self.running:
            client_socket, addr = self.accept_connection()
            
            if client_socket:
                if self.handshake(client_socket):
                    self.clients.append(client_socket)
                    print(f"WebSocket connection established with {addr}")
                    self.send_message(client_socket, {"status": "connected"})
                else:
                    client_socket.close()
                    
            disconnected = []
            for client in self.clients:
                message = self.receive_message(client)
                
                if message == 'CLOSE':
                    disconnected.append(client)
                elif message:
                    self.handle_message(client, message)
                    
            for client in disconnected:
                try:
                    client.close()
                except:
                    pass
                self.clients.remove(client)
                print("Client disconnected")
                
            gc.collect()
            time.sleep(0.01)
            
    def handle_message(self, client, message):
        try:
            data = json.loads(message)
            print(f"Received: {data}")
            
            if 'action' in data:
                response = self.process_action(data)
                self.send_message(client, response)
            else:
                self.send_message(client, {"error": "No action specified"})
                
        except ValueError:
            self.send_message(client, {"error": "Invalid JSON"})
        except Exception as e:
            self.send_message(client, {"error": str(e)})
            
    def process_action(self, data):
        action = data.get('action')
        
        if action == 'turn_on':
            return {"status": "success", "action": "turn_on", "state": "on"}
        elif action == 'turn_off':
            return {"status": "success", "action": "turn_off", "state": "off"}
        elif action == 'status':
            return {"status": "success", "device": "ESP32", "uptime": time.time()}
        elif action == 'ping':
            return {"status": "success", "message": "pong"}
        else:
            return {"status": "error", "message": f"Unknown action: {action}"}


class IoTDevice:
    def __init__(self):
        self.ws_server = WebSocketServer(port=8080)
        self.led = None
        try:
            self.led = Pin(2, Pin.OUT)
        except:
            print("LED pin not available")
            
    def process_action(self, data):
        action = data.get('action')
        
        if action == 'turn_on':
            if self.led:
                self.led.on()
            return {"status": "success", "action": "turn_on", "state": "on"}
        elif action == 'turn_off':
            if self.led:
                self.led.off()
            return {"status": "success", "action": "turn_off", "state": "off"}
        elif action == 'toggle':
            if self.led:
                self.led.value(not self.led.value())
            state = "on" if self.led and self.led.value() else "off"
            return {"status": "success", "action": "toggle", "state": state}
        elif action == 'status':
            state = "on" if self.led and self.led.value() else "off"
            return {
                "status": "success",
                "device": "ESP32",
                "led_state": state,
                "uptime": time.time(),
                "memory_free": gc.mem_free()
            }
        elif action == 'ping':
            return {"status": "success", "message": "pong"}
        else:
            return {"status": "error", "message": f"Unknown action: {action}"}
            
    def start(self):
        self.ws_server.process_action = self.process_action
        self.ws_server.start()
        print("IoT Device WebSocket server ready")
        self.ws_server.run()


def connect_wifi(ssid, password):
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    
    if not wlan.isconnected():
        print(f'Connecting to {ssid}...')
        wlan.connect(ssid, password)
        
        timeout = 10
        while not wlan.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
            
    if wlan.isconnected():
        print('Network connected!')
        print('IP address:', wlan.ifconfig()[0])
        return True
    else:
        print('Failed to connect to WiFi')
        return False


